import java.sql.*;

public class DMLOperations {
    public static void main(String[] args) {
        String url = "jdbc:mysql://localhost:3306/company";
        String user = "root";
        String password = "password";

        try (Connection conn = DriverManager.getConnection(url, user, password)) {

            // INSERT using PreparedStatement (prevents SQL injection)
            String insertSQL = "INSERT INTO employees (name, department, salary) VALUES (?, ?, ?)";
            try (PreparedStatement pstmt = conn.prepareStatement(insertSQL)) {
                pstmt.setString(1, "Amit Kumar");
                pstmt.setString(2, "IT");
                pstmt.setInt(3, 55000);
                int rows = pstmt.executeUpdate();
                System.out.println("Inserted: " + rows + " row(s)");
            }

            // UPDATE using PreparedStatement
            String updateSQL = "UPDATE employees SET salary = ? WHERE department = ?";
            try (PreparedStatement pstmt = conn.prepareStatement(updateSQL)) {
                pstmt.setInt(1, 60000);
                pstmt.setString(2, "IT");
                int rows = pstmt.executeUpdate();
                System.out.println("Updated: " + rows + " row(s)");
            }

            // SELECT with WHERE and ORDER BY
            String selectSQL = "SELECT * FROM employees WHERE salary > ? ORDER BY salary DESC";
            try (PreparedStatement pstmt = conn.prepareStatement(selectSQL)) {
                pstmt.setInt(1, 40000);
                ResultSet rs = pstmt.executeQuery();
                while (rs.next()) {
                    System.out.println(rs.getInt("emp_id") + ": " + 
                        rs.getString("name") + " - " + rs.getInt("salary"));
                }
            }

        } catch (SQLException e) {
            e.printStackTrace();
        }
    }
}
